class Solution:
    def baseUnitConversions(self, conversions):
        MOD = 10**9 + 7
        n = len(conversions) + 1
        parent = {}
        for s, t, f in conversions:
            parent[t] = (s, f)
        res = []
        for i in range(n):
            cur = i
            prod = 1
            while cur != 0:
                s, f = parent[cur]
                prod = (prod * f) % MOD
                cur = s
            res.append(prod % MOD)
        return res

