class Solution:
    def baseUnitConversions(self, conversions):
        MOD = 10**9 + 7
        n = len(conversions) + 1
        adj = [[] for _ in range(n)]
        for s, t, f in conversions:
            adj[s].append((t, f))
        res = [0] * n
        res[0] = 1
        stack = [0]
        while stack:
            u = stack.pop()
            for t, f in adj[u]:
                res[t] = (res[u] * f) % MOD
                stack.append(t)
        return res

